import{_ as a,c as s,o as e,a7 as t}from"./chunks/framework.BQb8NfN9.js";const h=JSON.parse('{"title":"Transformer","description":"","frontmatter":{},"headers":[],"relativePath":"ai/llm/transformer.md","filePath":"ai/llm/transformer.md","lastUpdated":1773670517000}'),r={name:"ai/llm/transformer.md"};function o(p,n,l,i,d,c){return e(),s("div",null,n[0]||(n[0]=[t(`<h1 id="transformer" tabindex="-1">Transformer <a class="header-anchor" href="#transformer" aria-label="Permalink to &quot;Transformer&quot;">​</a></h1><blockquote><p>2017 年 Google 论文 <em>&quot;Attention Is All You Need&quot;</em> 提出了 Transformer 架构，彻底改变了 NLP 乃至整个深度学习的格局。GPT、BERT、LLaMA……今天几乎所有大模型的底座都是 Transformer。这篇文档从「为什么需要它」出发，逐层拆解每一个组件，力求让你<strong>看完就真正理解</strong>。</p></blockquote><hr><h2 id="一、从-rnn-的痛点说起" tabindex="-1">一、从 RNN 的痛点说起 <a class="header-anchor" href="#一、从-rnn-的痛点说起" aria-label="Permalink to &quot;一、从 RNN 的痛点说起&quot;">​</a></h2><p>在 Transformer 之前，处理序列（文本、语音）的主流模型是 <strong>RNN / LSTM / GRU</strong>。它们的核心思路是「一步一步读」：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x₁ → h₁ → x₂ → h₂ → x₃ → h₃ → ... → xₙ → hₙ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这带来了两个致命问题：</p><table tabindex="0"><thead><tr><th>问题</th><th>说明</th></tr></thead><tbody><tr><td><strong>无法并行</strong></td><td>第 t 步的隐藏状态 hₜ 依赖 hₜ₋₁，必须串行计算，GPU 的并行能力被浪费</td></tr><tr><td><strong>长距离遗忘</strong></td><td>句子很长时，前面的信息传到后面已经「衰减」了。LSTM 的门机制缓解了但没根治</td></tr></tbody></table><p><strong>Transformer 的回答</strong>：扔掉循环结构，用 <strong>Attention（注意力）</strong> 让每个位置<strong>直接</strong>关注序列中的任意位置，一步到位、完全并行。</p><hr><h2 id="二、整体架构-一张图看全貌" tabindex="-1">二、整体架构：一张图看全貌 <a class="header-anchor" href="#二、整体架构-一张图看全貌" aria-label="Permalink to &quot;二、整体架构：一张图看全貌&quot;">​</a></h2><p>Transformer 是一个 <strong>Encoder–Decoder</strong> 结构（以原始论文为例）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌────────────────────────────────────────┐</span></span>
<span class="line"><span>                │            Transformer                 │</span></span>
<span class="line"><span>                │                                        │</span></span>
<span class="line"><span>  输入序列 ───▶ │  ┌──────────┐      ┌──────────┐       │ ───▶ 输出序列</span></span>
<span class="line"><span>  (源语言)      │  │ Encoder  │ ───▶ │ Decoder  │       │     (目标语言)</span></span>
<span class="line"><span>                │  │  × N层   │      │  × N层   │       │</span></span>
<span class="line"><span>                │  └──────────┘      └──────────┘       │</span></span>
<span class="line"><span>                └────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><strong>Encoder</strong>（编码器）：读入完整输入序列，输出一组「理解后的表示」。</li><li><strong>Decoder</strong>（解码器）：基于 Encoder 的输出，逐步生成目标序列。</li><li>原论文中 N = 6，即 Encoder 和 Decoder 各有 6 层堆叠。</li></ul><blockquote><p><strong>变体提示</strong>：后来的模型并非都用完整的 Encoder-Decoder。</p><ul><li><strong>BERT</strong>：只用 Encoder（擅长理解任务）。</li><li><strong>GPT</strong>：只用 Decoder（擅长生成任务）。</li><li><strong>T5</strong>：仍用 Encoder-Decoder。</li></ul></blockquote><hr><h2 id="三、核心组件逐一拆解" tabindex="-1">三、核心组件逐一拆解 <a class="header-anchor" href="#三、核心组件逐一拆解" aria-label="Permalink to &quot;三、核心组件逐一拆解&quot;">​</a></h2><h3 id="_3-1-输入表示-词嵌入-位置编码" tabindex="-1">3.1 输入表示：词嵌入 + 位置编码 <a class="header-anchor" href="#_3-1-输入表示-词嵌入-位置编码" aria-label="Permalink to &quot;3.1 输入表示：词嵌入 + 位置编码&quot;">​</a></h3><p>Transformer 没有循环，也没有卷积，所以它<strong>天生不知道词的先后顺序</strong>。为了让模型感知位置信息，需要在词嵌入（Word Embedding）上<strong>加上</strong>位置编码（Positional Encoding）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入表示 = Embedding(token) + PositionalEncoding(position)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="为什么是「加」而不是「拼接」" tabindex="-1">为什么是「加」而不是「拼接」？ <a class="header-anchor" href="#为什么是「加」而不是「拼接」" aria-label="Permalink to &quot;为什么是「加」而不是「拼接」？&quot;">​</a></h4><p>拼接会增大维度、增加参数量。实验表明，加法在不增加维度的前提下效果足够好——位置信息和语义信息在同一个向量空间里「叠加」。</p><h4 id="位置编码怎么算" tabindex="-1">位置编码怎么算？ <a class="header-anchor" href="#位置编码怎么算" aria-label="Permalink to &quot;位置编码怎么算？&quot;">​</a></h4><p>论文使用<strong>正弦-余弦函数</strong>生成位置编码：</p><p>$$PE_{(pos, 2i)} = \\sin\\left(\\frac{pos}{10000^{2i/d_{model}}}\\right)$$</p><p>$$PE_{(pos, 2i+1)} = \\cos\\left(\\frac{pos}{10000^{2i/d_{model}}}\\right)$$</p><ul><li><code>pos</code>：该 token 在序列中的位置（0, 1, 2, ...）。</li><li><code>i</code>：向量的第 i 个维度。</li><li><code>d_model</code>：嵌入向量的总维度（论文中为 512）。</li></ul><p><strong>直觉理解</strong>：不同维度的正弦/余弦频率不同，组合起来每个位置都能得到<strong>唯一的编码</strong>，就像用不同频率的信号来编码坐标。而且正弦函数天然具有「相对位置可通过线性变换表达」的数学性质，便于模型学习相对距离。</p><hr><h3 id="_3-2-self-attention-transformer-的灵魂" tabindex="-1">3.2 Self-Attention：Transformer 的灵魂 <a class="header-anchor" href="#_3-2-self-attention-transformer-的灵魂" aria-label="Permalink to &quot;3.2 Self-Attention：Transformer 的灵魂&quot;">​</a></h3><p><strong>Self-Attention（自注意力）</strong> 是整个架构最核心的创新。一句话概括：</p><blockquote><p><strong>让序列中的每个词，都能「看到」并「关注」序列中所有其它词，从而获得上下文感知的表示。</strong></p></blockquote><h4 id="_3-2-1-生活中的类比" tabindex="-1">3.2.1 生活中的类比 <a class="header-anchor" href="#_3-2-1-生活中的类比" aria-label="Permalink to &quot;3.2.1 生活中的类比&quot;">​</a></h4><p>想象你在读一句话：</p><blockquote><p>&quot;小明把<strong>它</strong>放在了桌子上，因为<strong>它</strong>太重了。&quot;</p></blockquote><p>你在理解第二个「它」时，大脑会自动回去看前文，判断「它」指的是什么。这就是注意力机制在做的事——<strong>动态地决定关注哪些位置</strong>。</p><h4 id="_3-2-2-q、k、v-三个角色" tabindex="-1">3.2.2 Q、K、V：三个角色 <a class="header-anchor" href="#_3-2-2-q、k、v-三个角色" aria-label="Permalink to &quot;3.2.2 Q、K、V：三个角色&quot;">​</a></h4><p>Self-Attention 为序列中的每个 token 生成三个向量：</p><table tabindex="0"><thead><tr><th>向量</th><th>全称</th><th>类比</th></tr></thead><tbody><tr><td><strong>Q</strong> (Query)</td><td>查询</td><td>&quot;我想找什么信息？&quot;</td></tr><tr><td><strong>K</strong> (Key)</td><td>键</td><td>&quot;我能提供什么信息？&quot;</td></tr><tr><td><strong>V</strong> (Value)</td><td>值</td><td>&quot;我实际包含的信息&quot;</td></tr></tbody></table><p>它们由输入向量 x 分别乘以三个可学习的权重矩阵 (W^Q, W^K, W^V) 得到：</p><p>$$Q = X \\cdot W^Q, \\quad K = X \\cdot W^K, \\quad V = X \\cdot W^V$$</p><h4 id="_3-2-3-计算过程-scaled-dot-product-attention" tabindex="-1">3.2.3 计算过程（Scaled Dot-Product Attention） <a class="header-anchor" href="#_3-2-3-计算过程-scaled-dot-product-attention" aria-label="Permalink to &quot;3.2.3 计算过程（Scaled Dot-Product Attention）&quot;">​</a></h4><p>$$\\text{Attention}(Q, K, V) = \\text{softmax}\\left(\\frac{QK^T}{\\sqrt{d_k}}\\right) V$$</p><p>分步理解：</p><p><strong>第一步：计算注意力分数</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Score = Q × Kᵀ    （矩阵乘法）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Q 的每一行（一个 token 的查询）和 K 的每一列（所有 token 的键）做点积。点积越大，表示这两个位置越「相关」。</p><p><strong>结果是一个 n×n 的矩阵</strong>，n 是序列长度，每个元素代表「token i 对 token j 的关注程度」。</p><p><strong>第二步：缩放（Scale）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Score = Score / √dₖ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>为什么要除以 (\\sqrt{d_k})？当维度 (d_k) 很大时，点积的数值会很大，导致 softmax 输出趋近于 one-hot（梯度极小，学不动）。除以 (\\sqrt{d_k}) 让数值回到合理范围。</p><p><strong>第三步：Softmax 归一化</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Weights = softmax(Score)   （每一行做 softmax）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>将分数转为概率分布（每行之和为 1），代表每个 token 对其它 token 的「注意力权重」。</p><p><strong>第四步：加权求和</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Output = Weights × V</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>用注意力权重对 V 做加权求和。最终每个 token 的输出，是所有 token 的 Value 按注意力权重的加权混合——<strong>包含了全局上下文信息</strong>。</p><h4 id="_3-2-4-一个具体例子" tabindex="-1">3.2.4 一个具体例子 <a class="header-anchor" href="#_3-2-4-一个具体例子" aria-label="Permalink to &quot;3.2.4 一个具体例子&quot;">​</a></h4><p>假设句子 &quot;I love cats&quot;，序列长度 n=3，(d_k)=4：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      Q × Kᵀ 得到 3×3 的注意力分数矩阵：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>              I     love   cats</span></span>
<span class="line"><span>      I    [ 0.9    0.1    0.3 ]     ← &quot;I&quot;   最关注自己</span></span>
<span class="line"><span>      love [ 0.2    0.8    0.7 ]     ← &quot;love&quot; 关注 &quot;love&quot; 和 &quot;cats&quot;</span></span>
<span class="line"><span>      cats [ 0.1    0.6    0.9 ]     ← &quot;cats&quot; 最关注自己，也关注 &quot;love&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      经过 softmax 后变成概率，再乘以 V，每个词获得了上下文感知的新表示。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h3 id="_3-3-multi-head-attention-多角度理解" tabindex="-1">3.3 Multi-Head Attention：多角度理解 <a class="header-anchor" href="#_3-3-multi-head-attention-多角度理解" aria-label="Permalink to &quot;3.3 Multi-Head Attention：多角度理解&quot;">​</a></h3><p>只做一次 Attention 相当于只从「一个角度」看句子。<strong>Multi-Head Attention 就是并行做多次 Attention</strong>，让模型从不同的角度（子空间）捕捉不同类型的关系：</p><p>$$\\text{MultiHead}(Q, K, V) = \\text{Concat}(\\text{head}_1, \\text{head}_2, \\dots, \\text{head}_h) \\cdot W^O$$</p><p>$$\\text{其中}\\ \\text{head}_i = \\text{Attention}(QW_i^Q,\\ KW_i^K,\\ VW_i^V)$$</p><p><strong>原论文</strong>：(d_{model}) = 512，h = 8 个头，每个头的维度 (d_k = d_v = 512/8 = 64)。</p><p><strong>直觉</strong>：</p><ul><li>某个头可能学会关注「语法关系」（主语 → 谓语）。</li><li>某个头可能学会关注「指代关系」（代词 → 名词）。</li><li>某个头可能学会关注「相邻词」（局部上下文）。</li></ul><p>多头并行运行，最后拼接 + 线性变换，融合所有视角的信息。</p><hr><h3 id="_3-4-残差连接-层归一化-add-norm" tabindex="-1">3.4 残差连接 + 层归一化（Add &amp; Norm） <a class="header-anchor" href="#_3-4-残差连接-层归一化-add-norm" aria-label="Permalink to &quot;3.4 残差连接 + 层归一化（Add &amp; Norm）&quot;">​</a></h3><p>Transformer 每个子层（Self-Attention 或 FFN）后面都有：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>output = LayerNorm(x + SubLayer(x))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>两个作用：</p><ul><li><strong>残差连接（Residual Connection）</strong>：<code>x + SubLayer(x)</code>。让梯度可以直接「跳过」子层回传，解决深层网络的梯度消失问题。即使子层什么也没学到（输出为 0），信息也不会丢失。</li><li><strong>层归一化（Layer Normalization）</strong>：对每个样本的特征维度做归一化（均值为 0、方差为 1），稳定训练、加速收敛。</li></ul><hr><h3 id="_3-5-前馈神经网络-feed-forward-network-ffn" tabindex="-1">3.5 前馈神经网络（Feed-Forward Network, FFN） <a class="header-anchor" href="#_3-5-前馈神经网络-feed-forward-network-ffn" aria-label="Permalink to &quot;3.5 前馈神经网络（Feed-Forward Network, FFN）&quot;">​</a></h3><p>每一层 Attention 之后，都会经过一个<strong>逐位置的全连接前馈网络</strong>：</p><p>$$FFN(x) = \\text{ReLU}(xW_1 + b_1)W_2 + b_2$$</p><ul><li>先升维（512 → 2048），经过 ReLU 激活，再降维（2048 → 512）。</li><li><strong>逐位置</strong>意味着每个 token 独立地通过同一个 FFN（参数共享），不涉及 token 间交互。</li></ul><p><strong>为什么需要 FFN？</strong><br> Self-Attention 擅长「混合不同位置的信息」，但它本质上是<strong>线性变换 + softmax</strong>，表达能力有限。FFN 引入了非线性（ReLU），增强模型的表达能力。可以理解为：Attention 负责「看哪里」，FFN 负责「想一想」。</p><hr><h3 id="_3-6-encoder-的完整结构" tabindex="-1">3.6 Encoder 的完整结构 <a class="header-anchor" href="#_3-6-encoder-的完整结构" aria-label="Permalink to &quot;3.6 Encoder 的完整结构&quot;">​</a></h3><p>把以上组件组合起来，<strong>一层 Encoder</strong> 长这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  Multi-Head Self-Attention │</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       Add &amp; Norm  ← 残差 + 层归一化</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────┴────────────┐</span></span>
<span class="line"><span>│    Feed-Forward Network    │</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       Add &amp; Norm  ← 残差 + 层归一化</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>           输出（送入下一层 Encoder）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>N 层 Encoder <strong>堆叠</strong>（每层结构相同，但参数独立），最终输出是对输入序列的<strong>深层语义理解表示</strong>。</p><hr><h3 id="_3-7-decoder-的完整结构" tabindex="-1">3.7 Decoder 的完整结构 <a class="header-anchor" href="#_3-7-decoder-的完整结构" aria-label="Permalink to &quot;3.7 Decoder 的完整结构&quot;">​</a></h3><p>Decoder 比 Encoder 多了一个子层——<strong>Cross-Attention</strong>（交叉注意力），用于关注 Encoder 的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标序列输入（右移一位）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>┌─────────────────────────────┐</span></span>
<span class="line"><span>│  Masked Multi-Head Self-Attention │  ← 只能看到「当前及之前」的位置</span></span>
<span class="line"><span>└────────────┬────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       Add &amp; Norm</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────┴────────────────┐</span></span>
<span class="line"><span>│  Multi-Head Cross-Attention    │  ← Q 来自 Decoder，K/V 来自 Encoder 输出</span></span>
<span class="line"><span>└────────────┬────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       Add &amp; Norm</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────┴────────────────┐</span></span>
<span class="line"><span>│    Feed-Forward Network        │</span></span>
<span class="line"><span>└────────────┬────────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       Add &amp; Norm</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>             ▼</span></span>
<span class="line"><span>           输出（送入下一层 Decoder）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h4 id="masked-self-attention-为什么要「遮挡」" tabindex="-1">Masked Self-Attention：为什么要「遮挡」？ <a class="header-anchor" href="#masked-self-attention-为什么要「遮挡」" aria-label="Permalink to &quot;Masked Self-Attention：为什么要「遮挡」？&quot;">​</a></h4><p>在生成任务中，Decoder 是<strong>自回归</strong>的——预测第 t 个词时，只能使用 1 到 t-1 个词的信息，不能「偷看」未来。</p><p>实现方式：在 softmax 之前，将注意力分数矩阵的<strong>右上三角</strong>设为 (-\\infty)，这样 softmax 后这些位置的权重为 0：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              位置1  位置2  位置3  位置4</span></span>
<span class="line"><span>    位置1  [  0.5    -∞     -∞     -∞  ]</span></span>
<span class="line"><span>    位置2  [  0.3    0.7    -∞     -∞  ]</span></span>
<span class="line"><span>    位置3  [  0.1    0.4    0.6    -∞  ]</span></span>
<span class="line"><span>    位置4  [  0.2    0.3    0.1    0.8 ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>位置3 只能看到位置1、2、3，看不到位置4。</p><h4 id="cross-attention-encoder-和-decoder-的桥梁" tabindex="-1">Cross-Attention：Encoder 和 Decoder 的桥梁 <a class="header-anchor" href="#cross-attention-encoder-和-decoder-的桥梁" aria-label="Permalink to &quot;Cross-Attention：Encoder 和 Decoder 的桥梁&quot;">​</a></h4><ul><li><strong>Q</strong>（查询）来自 Decoder 当前层的输出——「我要找什么」。</li><li><strong>K 和 V</strong> 来自 Encoder 的最终输出——「源序列提供的信息」。</li></ul><p>这让 Decoder 在生成每个词时，都能<strong>回头看源序列</strong>，找到最相关的部分。比如翻译时，生成法语单词会去 attend 对应的英语单词。</p><hr><h2 id="四、最终输出层" tabindex="-1">四、最终输出层 <a class="header-anchor" href="#四、最终输出层" aria-label="Permalink to &quot;四、最终输出层&quot;">​</a></h2><p>Decoder 最后一层的输出，经过一个<strong>线性层 + Softmax</strong>，映射到词表大小的概率分布：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Decoder 输出 → Linear(d_model → vocab_size) → Softmax → 概率分布</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>概率最高的词（或采样得到的词）就是模型预测的下一个 token。</p><hr><h2 id="五、训练相关" tabindex="-1">五、训练相关 <a class="header-anchor" href="#五、训练相关" aria-label="Permalink to &quot;五、训练相关&quot;">​</a></h2><h3 id="_5-1-损失函数" tabindex="-1">5.1 损失函数 <a class="header-anchor" href="#_5-1-损失函数" aria-label="Permalink to &quot;5.1 损失函数&quot;">​</a></h3><p>标准的<strong>交叉熵损失（Cross-Entropy Loss）</strong>：比较模型输出的概率分布与真实标签（one-hot）的差异。</p><h3 id="_5-2-优化器与学习率" tabindex="-1">5.2 优化器与学习率 <a class="header-anchor" href="#_5-2-优化器与学习率" aria-label="Permalink to &quot;5.2 优化器与学习率&quot;">​</a></h3><p>论文使用 Adam 优化器，并设计了<strong>带 warmup 的学习率调度</strong>：</p><p>$$lr = d_{model}^{-0.5} \\cdot \\min(step^{-0.5},\\ step \\cdot warmup_steps^{-1.5})$$</p><p>前 warmup_steps 步线性增大学习率，之后按步数的平方根衰减。这个策略在 Transformer 训练中非常重要——过早用大学习率会导致训练不稳定。</p><h3 id="_5-3-teacher-forcing" tabindex="-1">5.3 Teacher Forcing <a class="header-anchor" href="#_5-3-teacher-forcing" aria-label="Permalink to &quot;5.3 Teacher Forcing&quot;">​</a></h3><p>训练 Decoder 时，每一步的输入用的是<strong>真实标签</strong>（而非模型自己的预测）。这叫 Teacher Forcing，能加速收敛、稳定训练。</p><hr><h2 id="六、为什么-transformer-如此成功" tabindex="-1">六、为什么 Transformer 如此成功？ <a class="header-anchor" href="#六、为什么-transformer-如此成功" aria-label="Permalink to &quot;六、为什么 Transformer 如此成功？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优势</th><th>说明</th></tr></thead><tbody><tr><td><strong>完全并行</strong></td><td>没有循环依赖，序列中所有位置同时计算，充分利用 GPU</td></tr><tr><td><strong>长距离建模</strong></td><td>任意两个位置之间只隔「一层 Attention」，信息路径长度为 O(1)，RNN 是 O(n)</td></tr><tr><td><strong>可扩展性强</strong></td><td>增大模型/数据/算力 → 性能持续提升（Scaling Law），这是大模型时代的基础</td></tr><tr><td><strong>灵活架构</strong></td><td>Encoder-only（BERT）、Decoder-only（GPT）、Encoder-Decoder（T5）都能用</td></tr><tr><td><strong>注意力可解释</strong></td><td>注意力权重可以可视化，一定程度上可以看到模型「在关注什么」</td></tr></tbody></table><hr><h2 id="七、复杂度分析" tabindex="-1">七、复杂度分析 <a class="header-anchor" href="#七、复杂度分析" aria-label="Permalink to &quot;七、复杂度分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>每层计算复杂度</th><th>序列依赖距离</th><th>可并行</th></tr></thead><tbody><tr><td>RNN</td><td>O(n · d²)</td><td>O(n)</td><td>否</td></tr><tr><td>CNN</td><td>O(k · n · d²)</td><td>O(logₖn)</td><td>是</td></tr><tr><td><strong>Transformer</strong></td><td><strong>O(n² · d)</strong></td><td><strong>O(1)</strong></td><td><strong>是</strong></td></tr></tbody></table><p>Transformer 的代价：<strong>Self-Attention 的 n² 复杂度</strong>。当序列很长（如 n=100,000）时，注意力矩阵占用的内存和计算量都很大。这也是后来各种「高效 Transformer」（如 Sparse Attention、Flash Attention、Linear Attention）要解决的问题。</p><hr><h2 id="八、从原始-transformer-到现代大模型" tabindex="-1">八、从原始 Transformer 到现代大模型 <a class="header-anchor" href="#八、从原始-transformer-到现代大模型" aria-label="Permalink to &quot;八、从原始 Transformer 到现代大模型&quot;">​</a></h2><p>原始 Transformer 之后，架构在持续演进：</p><table tabindex="0"><thead><tr><th>演进方向</th><th>代表</th><th>说明</th></tr></thead><tbody><tr><td>Encoder-only</td><td>BERT (2018)</td><td>双向注意力，擅长理解/分类/抽取</td></tr><tr><td>Decoder-only</td><td>GPT 系列 (2018-)</td><td>自回归生成，擅长文本生成</td></tr><tr><td>Encoder-Decoder</td><td>T5 (2019)</td><td>统一的文本到文本框架</td></tr><tr><td>位置编码改进</td><td>RoPE (2021)</td><td>旋转位置编码，支持更好的长度外推</td></tr><tr><td>注意力优化</td><td>Flash Attention (2022)</td><td>IO 感知的高效注意力实现</td></tr><tr><td>激活函数改进</td><td>SwiGLU</td><td>替代 ReLU，提升 FFN 表达能力</td></tr><tr><td>归一化改进</td><td>RMSNorm, Pre-Norm</td><td>更稳定的归一化方式和放置位置</td></tr><tr><td>超长上下文</td><td>Ring Attention 等</td><td>支持百万级 token 的上下文窗口</td></tr></tbody></table><hr><h2 id="九、总结" tabindex="-1">九、总结 <a class="header-anchor" href="#九、总结" aria-label="Permalink to &quot;九、总结&quot;">​</a></h2><p>用一句话串起整个 Transformer：</p><blockquote><p><strong>把输入序列通过词嵌入 + 位置编码变成向量，经过多层「Self-Attention → FFN」反复提炼，每一层都让每个 token 充分感知全局上下文，最终输出高质量的语义表示。</strong></p></blockquote><p>核心记忆点：</p><ol><li><strong>Attention 是灵魂</strong>：Q、K、V 三个矩阵，点积 → 缩放 → softmax → 加权求和。</li><li><strong>Multi-Head 看多面</strong>：多个头并行，捕捉不同类型的关系。</li><li><strong>位置编码补顺序</strong>：正弦/余弦函数为无循环结构注入位置信息。</li><li><strong>残差 + 层归一化</strong>：保证深层网络训练稳定。</li><li><strong>FFN 加非线性</strong>：Attention 看哪里，FFN 想一想。</li><li><strong>Mask 防偷看</strong>：Decoder 的自回归特性靠 mask 保证。</li></ol><p>理解了这些，你就掌握了当今几乎所有大模型的底层架构基础。</p>`,131)]))}const u=a(r,[["render",o]]);export{h as __pageData,u as default};
